from typing import List


def sort_numbers(numbers: str) -> str:
    """ Input is a space-delimited string of numberals from 'zero' to 'nine'.
    Valid choices are 'zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight' and 'nine'.
    Return the string with numbers sorted from smallest to largest
    >>> sort_numbers('three one five')
    'one three five'
    """
    if not numbers.strip():
        return ""

    word_to_val = {
        'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4,
        'five': 5, 'six': 6, 'seven': 7, 'eight': 8, 'nine': 9
    }

    val_to_word = {v: k for k, v in word_to_val.items()}

    input_words = numbers.split()
    numeric_values = [word_to_val[word.lower()] for word in input_words]
    numeric_values.sort()

    return ' '.join(val_to_word[val] for val in numeric_values)

def strlen(string: str) -> int:
    """ Return length of given string
    >>> strlen('')
    0
    >>> strlen('abc')
    3
    """
    if not isinstance(string, str):
        raise TypeError("Input must be a string")
    return len(string)

def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    # Start searching from n-1 downwards to find the largest divisor
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i
    return 1

