def is_prime(num: int) -> bool:
    """
    Determines if a given number is prime using an efficient primality test.
    """
    if num < 2:
        return False
    if num == 2 or num == 3:
        return True
    if num % 2 == 0 or num % 3 == 0:
        return False
    i = 5
    while i * i <= num:
        if num % i == 0 or num % (i + 2) == 0:
            return False
        i += 6
    return True

def prime_fib(n: int) -> int:
    """
    prime_fib returns n-th number that is a Fibonacci number and it's also prime.
    """
    count = 0
    prev = 0
    curr = 1

    while count < n:
        # generate_next_fibonacci logic
        next_fib = prev + curr
        prev = curr
        curr = next_fib

        if is_prime(curr):
            count += 1
            if count == n:
                return curr

