def count_up_to(n):
    if n < 2:
        return []

    primes = []
    # Sieve of Eratosthenes approach for efficiency
    is_prime = [True] * n
    is_prime[0] = is_prime[1] = False

    for p in range(2, n):
        if is_prime[p]:
            primes.append(p)
            # Mark multiples of p as not prime
            for i in range(p * p, n, p):
                is_prime[i] = False

    return primes

