def calculate_signed_digit_sum(num):
    """
    Calculates the sum of digits based on the signed-digit rule:
    - If negative, the first digit is negative, others are positive.
    - If positive, all digits are positive.
    """
    s = str(num)
    if not s:
        return 0

    if s[0] == '-':
        # Handle negative number logic: -123 -> -1, 2, 3
        if len(s) == 1:
            return 0
        first_digit = -int(s[1])
        remaining_digits_sum = sum(int(d) for d in s[2:])
        return first_digit + remaining_digits_sum
    else:
        # Handle positive number logic
        return sum(int(d) for d in s)

