def sort_array(arr):
    """
    Sorts an array of integers based on the number of set bits (population count)
    in their binary representation (ascending), and then by their decimal value (ascending).

    For negative integers, the bit count is calculated based on the two's complement
    representation. In Python, bin(n) for negative numbers returns '-0b...', so we
    simulate the bit count for a 64-bit integer to ensure consistent behavior.
    """
    def get_bit_count(n):
        if n < 0:
            # Simulate 64-bit two's complement for negative numbers
            return bin(n & 0xFFFFFFFFFFFFFFFF).count('1')
        return bin(n).count('1')

    # Sort using a tuple as the key: (primary: bit_count, secondary: decimal_value)
    return sorted(arr, key=lambda x: (get_bit_count(x), x))

