    """
    Sorts an array of integers according to the number of ones in their binary 
    representation in ascending order. For similar number of ones, sorts based 
    on decimal value.
    """
    def get_bit_count(n):
        if n >= 0:
            return bin(n).count('1')
        else:
            # Standard two's complement representation for bit counting
            # Using 64-bit as a common standard for bitwise operations in Python
            return bin(n & 0xFFFFFFFFFFFFFFFF).count('1')

    # Primary key: bit count, Secondary key: decimal value
    return sorted(arr, key=lambda x: (get_bit_count(x), x))

