def maximum(arr, k):
    if k == 0:
        return []

    # Sort the array in descending order to easily pick the top k elements
    # We use a copy to preserve the original input collection's integrity
    sorted_desc = sorted(arr, reverse=True)
    top_k = sorted_desc[:k]

    # The resulting collection must be sorted in ascending order
    return sorted(top_k)

def add_elements(arr, k):
    """Returns the sum of elements with at most two digits from the first k elements."""
    total_sum = 0
    # Process only the first k elements
    for i in range(k):
        element = arr[i]
        # An element has at most two digits if its absolute value is less than 100
        if -100 < element < 100:
            total_sum += element
    return total_sum

