    """
    Validates a date string based on specific rules:
    1. Not empty.
    2. Format mm-dd-yyyy (10 characters).
    3. Month between 1 and 12.
    4. Days: 1-31 for (1,3,5,7,8,10,12), 1-30 for (4,6,9,11), 1-29 for (2).
    """
    if not date or len(date) != 10:
        return False

    parts = date.split('-')
    if len(parts) != 3:
        return False

    m_str, d_str, y_str = parts

    if not (m_str.isdigit() and d_str.isdigit() and y_str.isdigit()):
        return False

    month = int(m_str)
    day = int(d_str)
    year = int(y_str)

