def can_arrange(arr):
    """
    Returns the largest index i such that arr[i] < arr[i-1].
    Returns -1 if no such index exists.
    """
    max_index = -1
    for i in range(1, len(arr)):
        if arr[i] < arr[i-1]:
            max_index = i
    return max_index

