def words_in_sentence(sentence):
    """
    Returns a string containing words from the original sentence whose lengths are prime numbers.
    """
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    # Tokenization: Split by single space
    words = sentence.split(' ')

    # Filtering: Keep words with prime lengths
    prime_length_words = []
    for word in words:
        if is_prime(len(word)):
            prime_length_words.append(word)

    # Reconstruction: Join with single space
    return " ".join(prime_length_words)

def order_by_points(nums):
    """
    Write a function which sorts the given list of integers
    in ascending order according to the sum of their digits.
    Note: if there are several items with similar sum of their digits,
    order them based on their index in original list.
    """
    def calculate_digit_sum(number):
        s = str(number)
        if not s:
            return 0

        if s[0] == '-':
            # For negative integers, the first digit is treated as negative,
            # and all subsequent digits are treated as positive.
            # Example: -123 -> -1 + 2 + 3 = 4
            first_digit = -int(s[1])
            remaining_digits = sum(int(d) for d in s[2:])
            return first_digit + remaining_digits
        else:
            # For positive integers, all digits are summed.
            return sum(int(d) for d in s)

    return sorted(nums, key=calculate_digit_sum)

