def double_the_difference(lst):
    """
    Given a list of numbers, return the sum of squares of the numbers
    in the list that are odd. Ignore numbers that are negative or not integers.
    """
    result = 0
    for x in lst:
        # Strict integer type check as per spec (exclude floats like 3.0)
        if isinstance(x, int):
            # Filter for positive integers (>= 0) and odd parity
            if x >= 0 and x % 2 != 0:
                result += x * x
    return result

