def solve(s):
    has_letter = any(c.isalpha() for c in s)

    if has_letter:
        result = []
        for char in s:
            result.append(char.swapcase())
        return "".join(result)
    else:
        return s[::-1]

def prime_length(string):
    """Write a function that takes a string and returns True if the string
    length is a prime number or False otherwise
    """
    n = len(string)

    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

def anti_shuffle(s):
    """
    Write a function that takes a string and returns an ordered version of it.
    Ordered version of string, is a string where all words (separated by space)
    are replaced by a new word where all the characters arranged in
    ascending order based on ascii value.
    Note: You should keep the order of words and blank spaces in the sentence.
    """
    res = []
    word_buffer = []

    for char in s:
        if char == ' ':
            if word_buffer:
                res.append("".join(sorted(word_buffer)))
                word_buffer = []
            res.append(char)
        else:
            word_buffer.append(char)

    if word_buffer:
        res.append("".join(sorted(word_buffer)))

    return "".join(res)

def sum_squares(lst):
    result_sum = 0
    for i in range(len(lst)):
        val = lst[i]
        if i % 3 == 0:
            # Rule: If index is multiple of 3, square it.
            # Note: Index 0 is a multiple of 3.
            result_sum += val ** 2
        elif i % 4 == 0:
            # Rule: If index is multiple of 4 and NOT 3, cube it.
            result_sum += val ** 3
        else:
            # Rule: Otherwise, no change.
            result_sum += val
    return result_sum
